insert into public.business_news_posts (id, business_id, title, body, image_path, created_at) values
('biz_001-news-01','biz_001','이번 주 베이글 라인업 안내','합정베이글클럽 이번 주 라인업은 플레인, 참깨, 블루베리, 올리브치즈, 무화과 호두까지 준비돼 있어요. 오전에는 담백한 종류가 먼저 많이 나가고, 주말에는 크림치즈 세트 문의가 많아 조금 더 넉넉하게 굽고 있습니다. 베이글은 당일 생산분 위주로 판매하고 있어서 늦은 시간에는 일부 품목이 조기 품절될 수 있어요. 찾으시는 맛이 있다면 방문 전에 가볍게 확인하고 오시는 걸 추천드려요.',null,'2026-04-14T12:00:00+09:00'::timestamptz),
('biz_001-news-02','biz_001','시즌 한정 딸기 크림치즈 출시','이번 주부터 합정베이글클럽에 시즌 한정 딸기 크림치즈가 추가됐어요. 과하게 달지 않게 만든 스타일이라 플레인이나 통밀 베이글과 같이 드시면 부담이 적고, 주말 브런치처럼 즐기기에도 잘 어울립니다. 매장에서 바로 발라드리는 조합 주문이 많아 아침 시간에는 준비 속도가 조금 느릴 수 있어요. 처음 드시는 분들은 기본 베이글에 반쪽 추가로 많이 선택하셔서 참고 부탁드려요.',null,'2026-04-14T03:00:00+09:00'::timestamptz),
('biz_002-news-01','biz_002','평일 점심 순두부 정식 안내','서교순두부식당은 점심시간에 순두부 정식 주문이 가장 많아요. 해물순두부, 우삼겹순두부, 김치순두부처럼 자주 찾는 메뉴는 빠르게 나가지만, 돌솥밥이 함께 나가다 보니 한꺼번에 주문이 몰리면 조리 시간이 조금 길어질 수 있습니다. 최근에는 덜 맵게 요청하시는 손님이 많아서 맵기 조절도 가능한 범위에서 도와드리고 있어요. 근처에서 따뜻한 한 끼 찾으시는 분들은 평일 이른 점심 시간대가 가장 편하게 이용 가능합니다.',null,'2026-04-13T17:00:00+09:00'::timestamptz),
('biz_002-news-02','biz_002','비 오는 날엔 전 메뉴 포장 가능','비 오는 날에는 뜨끈한 국물 메뉴 포장 문의가 많아서 안내드려요. 서교순두부식당은 순두부류 전 메뉴 포장이 가능하고, 반찬은 매장 상황에 맞춰 기본 구성으로 함께 준비해드리고 있습니다. 다만 계란이 들어가는 메뉴는 포장 이동 시간에 따라 식감 차이가 생길 수 있어 매장 식사와 조금 다르게 느껴질 수 있어요. 늦은 저녁 시간에는 재료 소진으로 일부 메뉴가 먼저 마감될 수 있으니 참고 부탁드립니다.','서교순두부식당/소식-02/image.webp','2026-04-13T08:00:00+09:00'::timestamptz),
('biz_002-news-03','biz_002','신메뉴 차돌된장순두부 시작','기존 메뉴보다 조금 더 진한 맛을 찾는 분들이 많아 차돌된장순두부를 새로 시작했어요. 구수한 된장 베이스에 차돌을 더해 식사감이 분명한 편이라 든든하게 드시고 싶을 때 추천드려요. 자극적인 맛보다는 편하게 계속 떠먹기 좋은 방향으로 간을 맞췄고, 함께 나가는 밑반찬도 조금 더 잘 어울리게 조정했습니다. 처음 방문하시는 분들이 기본 순두부와 많이 고민하셔서, 매장에서는 취향에 맞게 간단히 설명드리고 있어요.',null,'2026-04-12T20:00:00+09:00'::timestamptz),
('biz_003-news-01','biz_003','봄 이불 세탁 접수 늘렸어요','망원클린24는 계절이 바뀌면서 이불 세탁 문의가 크게 늘어 이번 주 접수량을 조금 더 확대했어요. 일반 이불과 극세사, 토퍼류는 소재에 따라 건조 시간이 달라 같은 날 완료가 어려운 경우도 있어 접수할 때 예상 일정을 함께 안내드리고 있습니다. 특히 주말에는 맡기고 찾으러 오시는 시간이 겹쳐 대기 시간이 생길 수 있어요. 부피가 큰 세탁물은 가급적 오전에 접수해주시면 더 안정적으로 처리할 수 있습니다.',null,'2026-04-12T07:00:00+09:00'::timestamptz),
('biz_003-news-02','biz_003','운동화 케어 할인 주간','자주 신는 흰 운동화나 캔버스화 세탁 문의가 많아 이번 주는 운동화 케어 접수 건에 한해 할인 적용 중이에요. 오염이 심한 부분은 기본 세탁만으로 완전히 지워지지 않을 수 있어 상태를 먼저 보고 안내드리고 있고, 접착이나 소재 손상 우려가 있는 제품은 무리해서 작업하지 않습니다. 생활 얼룩 정리와 전체적인 톤 정돈을 중심으로 진행한다고 생각해주시면 좋아요. 맡기실 때 신발 상태를 사진으로 남겨두고 비교 설명도 함께 도와드리고 있습니다.',null,'2026-04-11T22:00:00+09:00'::timestamptz),
('biz_004-news-01','biz_004','저녁 체험 수업 오픈','합정필라테스랩에서 퇴근 후 방문하시는 분들을 위해 저녁 체험 수업 시간을 추가했어요. 처음 오시는 분들은 기구 사용이 어렵지 않을까 걱정하시는데, 체형과 운동 경험을 간단히 확인한 뒤 무리 없는 동작부터 진행하고 있어서 입문 수업으로 많이 선택하고 있습니다. 최근에는 오래 앉아 있는 직장인분들의 어깨와 골반 밸런스 상담이 가장 많았어요. 체험 수업은 시간대별 인원이 달라 원하는 분위기가 있다면 미리 문의 후 예약하시는 걸 추천드립니다.',null,'2026-04-11T11:00:00+09:00'::timestamptz),
('biz_004-news-02','biz_004','코어 집중 프로그램 안내','이번 달에는 복부와 골반 안정성을 중심으로 한 코어 집중 프로그램 문의가 많아 관련 수업 안내를 조금 더 자세히 드리고 있어요. 합정필라테스랩 수업은 강하게만 하는 방식보다 자세를 정확히 인지하고 반복하는 데 더 비중을 두고 있어, 운동을 쉬었다가 다시 시작하는 분들도 부담이 적은 편입니다. 수업 후에는 집에서 따라 할 수 있는 간단한 스트레칭 팁도 함께 설명드려요. 장시간 앉아 있거나 허리 불편감을 자주 느끼는 분들이 특히 많이 찾고 있습니다.',null,'2026-04-11T01:00:00+09:00'::timestamptz),
('biz_005-news-01','biz_005','봄 컬러 아트 샘플 업데이트','홍대앞네일무드에 봄 시즌 컬러 아트 샘플을 새로 정리해두었어요. 핑크나 코랄 계열처럼 밝은 톤도 있지만, 은은한 시럽 컬러나 짧은 손톱에 어울리는 단정한 디자인 문의가 특히 많아서 데일리용 샘플을 조금 더 늘렸습니다. 과한 파츠보다는 손에 자연스럽게 올라가는 무드를 찾으시는 분들이 많아 전체적인 조합도 가볍게 다듬었어요. 방문 전에 원하는 느낌의 사진을 보여주시면 비슷한 결로 추천드리기 훨씬 수월합니다.','홍대앞네일무드/소식-01/image.webp','2026-04-10T13:00:00+09:00'::timestamptz),
('biz_005-news-02','biz_005','평일 낮 젤 제거 포함 예약 가능','최근에는 기존 젤 제거 후 재시술까지 한 번에 받으려는 분들이 많아 평일 낮 시간대 예약 동선을 조금 조정했어요. 제거만 필요한 경우와 바로 아트까지 이어지는 경우가 시간 차이가 커서, 홍대앞네일무드에서는 예약 전에 현재 손 상태를 간단히 알려주시면 훨씬 정확하게 안내드릴 수 있습니다. 손톱이 얇아진 분들은 컬러보다 케어 위주로 먼저 권해드리는 편이고, 유지력을 위해 생활 습관에 맞는 마감도 같이 설명드리고 있어요.',null,'2026-04-10T04:00:00+09:00'::timestamptz),
('biz_006-news-01','biz_006','원두 라인업 바뀌었어요','서교커피스탠드는 이번 주부터 에스프레소 블렌드와 필터 원두 구성을 조금 바꿨어요. 산미가 너무 강하지 않은 쪽을 찾는 손님이 많아서, 매일 마셔도 부담 적은 밸런스로 조정한 것이 가장 큰 변화입니다. 우유가 들어가는 메뉴에서는 고소한 맛이 더 잘 느껴지고, 필터는 오후에 천천히 마시기 좋은 향 중심으로 준비하고 있어요. 커피 취향을 말씀해주시면 기존 메뉴 안에서 가장 비슷한 방향으로 추천드릴게요.',null,'2026-04-09T16:00:00+09:00'::timestamptz),
('biz_006-news-02','biz_006','테이크아웃 컵 홀더 문구 이벤트','날씨가 풀리면서 테이크아웃 손님이 많아져 컵 홀더에 짧은 문구를 적어드리는 작은 이벤트를 시작했어요. 서교커피스탠드는 매장이 크지 않아 오래 머무르기보다 가볍게 들렀다 가시는 분들이 많은데, 이런 소소한 요청을 좋아해주셔서 한동안 이어가보려 합니다. 주문이 몰리는 오전 시간에는 모든 컵에 적용되지 않을 수 있지만 가능한 범위에서는 챙겨드릴게요. 친구에게 건네는 커피나 간단한 선물용 주문 때 특히 반응이 좋았습니다.',null,'2026-04-09T05:00:00+09:00'::timestamptz),
('biz_006-news-03','biz_006','주말엔 스콘 수량 늘립니다','커피와 함께 간단히 드실 수 있는 스콘 문의가 많아 주말에는 기본 수량을 조금 더 준비해요. 버터향이 진한 플레인과 잼이 잘 어울리는 메뉴 위주로 운영하고 있고, 늦은 오후에는 남은 종류가 한정될 수 있습니다. 서교커피스탠드는 음료가 메인인 공간이라 베이커리 종류를 크게 늘리기보다는 잘 나가는 조합 위주로 천천히 맞춰가고 있어요. 커피와 함께 가볍게 즐기실 분들은 점심 전후 시간대 방문이 가장 선택 폭이 넓습니다.',null,'2026-04-08T18:00:00+09:00'::timestamptz),
('biz_007-news-01','biz_007','등심 돈가스 재료 수급 정상화','합정돈가스정원에서 한동안 빨리 소진되던 등심 돈가스 재료 수급이 다시 안정돼서 안내드려요. 최근에는 기본 메뉴를 찾는 손님이 많았는데, 튀김옷이 너무 두껍지 않고 고기 식감이 살아 있는 스타일을 선호하신다는 의견이 많아 지금 구성을 유지하고 있습니다. 점심 피크 시간에는 주문이 몰려 테이블 회전이 조금 느릴 수 있어요. 바삭한 상태로 가장 편하게 드시려면 평일 오픈 직후나 저녁 초반 방문을 추천드립니다.',null,'2026-04-08T05:00:00+09:00'::timestamptz),
('biz_007-news-02','biz_007','매운 소스 추가 요청 가능','기본 소스보다 조금 더 자극적인 맛을 찾는 분들이 있어 매운 소스 요청 옵션을 같이 운영하고 있어요. 합정돈가스정원의 기본 돈가스는 누구나 편하게 먹기 좋은 방향이라 맵기 자체는 세지 않은 편인데, 느끼함을 줄이고 싶다는 요청이 있어 따로 곁들일 수 있게 준비했습니다. 처음부터 듬뿍 붓기보다는 조금씩 곁들여 드시는 쪽을 많이 추천드려요. 치즈나 안심 메뉴와도 생각보다 잘 어울려서 재주문하시는 분들이 꽤 있습니다.',null,'2026-04-07T19:00:00+09:00'::timestamptz),
('biz_008-news-01','biz_008','주말 아침 요가 클래스 모집','망원요가하우스에서 주말 아침 클래스 문의가 늘어 이번 달에는 입문자 중심 소규모 수업을 추가로 운영해요. 몸이 굳어 있는 상태에서 무리하게 버티는 방식보다 호흡과 정렬을 먼저 익히는 흐름이라 처음 해보는 분들도 따라오기 어렵지 않습니다. 특히 평일에 운동 시간을 내기 어려운 분들이 가볍게 시작하기 좋은 반응을 보여주셨어요. 요가 매트 대여도 가능하지만 개인 매트를 사용하시는 분들은 더 편하게 집중하실 수 있습니다.',null,'2026-04-07T06:00:00+09:00'::timestamptz),
('biz_008-news-02','biz_008','수업 전후 스트레칭 가이드 제공','수업만 듣고 끝나는 것보다 집에서도 짧게 이어갈 수 있게, 망원요가하우스에서는 최근 수업 후 스트레칭 포인트를 간단히 정리해서 안내드리고 있어요. 어깨가 자주 말리거나 허벅지 뒤쪽이 뻣뻣한 분들은 작은 루틴만 꾸준히 해도 체감이 크다는 이야기가 많았습니다. 수업에서 했던 동작을 무리하게 반복하기보다는 호흡을 맞추는 기본 자세 위주로 구성해 드리고 있어요. 장시간 앉아서 일하는 분들에게 특히 도움이 된다는 피드백이 많았습니다.',null,'2026-04-06T21:00:00+09:00'::timestamptz),
('biz_008-news-03','biz_008','저녁 릴렉스 클래스 시간 조정','퇴근 후 방문하시는 분들이 조금 더 여유 있게 올 수 있도록 저녁 릴렉스 클래스 시작 시간을 소폭 조정했어요. 하루 종일 긴장된 몸을 천천히 풀어주는 흐름이라 격한 운동보다는 회복감을 원하는 분들이 많이 찾고 있습니다. 최근에는 목과 어깨가 뻐근한 상태로 오시는 분들이 많아 상체 이완 비중도 조금 높였어요. 조용한 분위기의 수업을 선호하시는 분들은 새 시간표가 더 잘 맞을 수 있으니 확인 후 예약 부탁드립니다.','망원요가하우스/소식-03/image.webp','2026-04-06T10:00:00+09:00'::timestamptz),
('biz_009-news-01','biz_009','단발 고객 커트 상담 늘렸어요','합정꽃길미용실은 최근 짧은 단발이나 중단발 정리 상담이 많아 관련 스타일 안내를 조금 더 자세히 도와드리고 있어요. 사진만 보고 똑같이 자르기보다는 머리숱과 얼굴형, 손질 가능 시간을 먼저 보고 길이와 층을 조정하는 방식이라 집에서의 재현이 어렵지 않다는 반응이 많았습니다. 특히 옆머리와 뒷머리 라인을 깔끔하게 정리해달라는 요청이 많아 세부 상담 시간이 조금 더 길어질 수 있어요. 처음 방문하시는 분들은 평소 손질 습관을 함께 말씀해주시면 좋습니다.',null,'2026-04-06T00:00:00+09:00'::timestamptz),
('biz_009-news-02','biz_009','염색 후 홈케어 안내 강화','톤다운 염색이나 자연스러운 브라운 계열 시술이 늘면서, 합정꽃길미용실에서는 시술 직후보다 집에서의 관리 방법을 더 자세히 설명드리고 있어요. 색이 금방 빠지는 경우는 모발 상태나 샴푸 습관 영향이 큰 편이라 제품 추천보다 생활 루틴을 먼저 조정해드리는 방식으로 안내 중입니다. 너무 어두워 보이지 않으면서도 차분한 느낌을 원하시는 분들이 많아 상담 시 참고 사진을 함께 보고 톤을 맞추고 있어요. 예약 간격을 조금 넉넉하게 잡아주시면 상담이 더 편합니다.',null,'2026-04-05T14:00:00+09:00'::timestamptz),
('biz_010-news-01','biz_010','바지 기장 수선 당일 접수 가능','서교생활수선은 요즘 바지 기장 수선 문의가 많아 기본 접수 동선을 조금 정리했어요. 단순 기장 줄임이나 허리 조정처럼 비교적 빠르게 가능한 작업은 당일 접수 후 안내드리는 경우가 많지만, 원단 두께나 마감 방식에 따라 완료 시간이 달라질 수 있습니다. 특히 데님처럼 스티치 색을 맞춰야 하는 작업은 확인할 부분이 많아 조금 더 여유가 필요해요. 입고 오시는 신발 높이나 원하는 핏을 설명해주시면 결과 차이가 훨씬 적습니다.',null,'2026-04-05T01:00:00+09:00'::timestamptz),
('biz_010-news-02','biz_010','가방 지퍼 교체 문의 안내','생활 수선 중에서도 가방 지퍼는 고장 원인이 다양해서 사진만으로 판단이 어려운 경우가 많아요. 서교생활수선에서는 지퍼 슬라이더 교체만으로 해결되는지, 전체 교체가 필요한지 실제 상태를 보고 먼저 설명드리고 있습니다. 천 손상이나 안감 문제까지 함께 있는 경우에는 단순 수선보다 시간이 더 걸릴 수 있어요. 자주 쓰는 가방일수록 임시 수선보다 오래 가는 방식으로 진행하는 편이 만족도가 높아서 그 방향으로 많이 안내드리고 있습니다.',null,'2026-04-04T14:00:00+09:00'::timestamptz),
('biz_010-news-03','biz_010','커튼 밑단 정리 예약 받습니다','이사철이라 커튼 길이 조정 문의가 늘어 관련 작업도 예약으로 받고 있어요. 집에서 대충 접어 쓰다가 결국 다시 맡기시는 경우가 많아서, 서교생활수선에서는 실제 설치 높이에 맞는 길이를 기준으로 재는 방법부터 먼저 안내드리고 있습니다. 얇은 쉬폰과 두꺼운 암막은 마감 방식이 달라 작업 시간이 다르고, 핀 구조에 따라 길이 체감도 달라질 수 있어요. 방문 전에 대략적인 사이즈와 원단 사진을 보내주시면 접수 과정이 훨씬 수월합니다.',null,'2026-04-04T01:00:00+09:00'::timestamptz),
('biz_011-news-01','biz_011','저녁 붕어빵 판매 다시 시작','날씨가 쌀쌀한 저녁 시간대 문의가 많아 망원붕어빵앞은 저녁 판매를 다시 길게 운영해요. 팥과 슈크림 기본 두 종류를 중심으로 준비하고, 반죽 상태를 보면서 굽기 때문에 한 번에 많은 수량을 바로 드리기 어려운 시간도 있습니다. 갓 구운 상태를 찾는 분들이 많아 잠깐 대기 후 받아가시는 경우가 잦아요. 지나가다 바로 사 가시는 손님이 많아서 늦은 시간에는 특정 맛이 먼저 끝날 수 있으니 참고 부탁드립니다.',null,'2026-04-03T15:00:00+09:00'::timestamptz),
('biz_011-news-02','biz_011','팥 붕어빵 반죽 비율 조정','최근에는 너무 달지 않은 간식을 찾는 분들이 많아 팥 붕어빵 반죽과 앙금 비율을 조금 손봤어요. 겉은 바삭하고 안은 답답하지 않게 먹히는 쪽을 목표로 해서, 예전보다 한 번에 두세 개 먹기 편하다는 반응이 많았습니다. 망원붕어빵앞은 길거리 간식 특성상 빠르게 받아가는 분들이 많지만, 식감이 가장 좋을 때 드실 수 있도록 굽는 속도를 일정하게 유지하려고 해요. 아이와 함께 오는 손님들이 많아 너무 뜨겁지 않게 식혀 드리는 요청도 가능합니다.',null,'2026-04-03T06:00:00+09:00'::timestamptz),
('biz_012-news-01','biz_012','생수 묶음 할인 안내','합정스몰마트는 자주 찾으시는 생필품 위주로 작은 할인 행사를 자주 하고 있어요. 이번 주에는 생수와 휴지처럼 집에서 바로 체감되는 품목 문의가 많아 묶음 구매 시 가격을 조금 낮춰 운영합니다. 대형 마트처럼 품목이 아주 많지는 않지만, 동네에서 급하게 필요한 물건을 편하게 사 갈 수 있도록 잘 나가는 제품 위주로 구성하고 있어요. 저녁 시간에는 퇴근길 방문이 몰려 일부 진열이 비는 속도가 빨라질 수 있어 필요하신 품목은 조금 이른 시간 방문을 권해드립니다.',null,'2026-04-02T17:00:00+09:00'::timestamptz),
('biz_012-news-02','biz_012','간단한 아침 대용 코너 정리','출근 전에 들르시는 손님들이 많아 합정스몰마트 입구 쪽 아침 대용 코너를 다시 정리했어요. 우유, 두유, 바나나, 샌드류처럼 바로 집어가기 좋은 상품을 한쪽에 모아두어서 짧게 들렀다 가기 편하다는 의견이 있었습니다. 기존에는 과자와 음료가 섞여 있어 찾기 어렵다는 말이 있었는데, 이번에는 사용 상황별로 묶어 배치해보는 방향으로 바꿨어요. 급하게 필요한 물건을 한 번에 찾는 경험을 조금 더 편하게 만드는 데 초점을 맞췄습니다.','합정스몰마트/소식-02/image.webp','2026-04-02T07:00:00+09:00'::timestamptz),
('biz_013-news-01','biz_013','브런치 플레이트 구성 바뀌었어요','서교브런치로프는 최근 가장 주문이 많았던 메뉴를 기준으로 브런치 플레이트 구성을 조금 손봤어요. 너무 무겁지 않게 먹고 싶다는 의견이 많아 샐러드 비중을 늘리고 빵과 사이드 조합을 가볍게 조정했습니다. 사진이 예쁘게 나오는 것보다 실제로 먹었을 때 밸런스가 편한 구성을 우선으로 맞췄어요. 늦은 오후에는 브런치 재료가 일부 소진될 수 있으니 식사 목적이라면 점심 전후 시간대 방문이 가장 안정적입니다.',null,'2026-04-01T22:00:00+09:00'::timestamptz),
('biz_013-news-02','biz_013','주말 대기 안내','주말에는 오픈 직후부터 한꺼번에 방문하시는 분들이 많아 대기 시간이 생길 수 있어요. 서교브런치로프는 테이블 간격과 조리 흐름상 많은 팀을 빠르게 받기보다 식사 템포를 유지하는 쪽을 선택하고 있어 대기 체감이 더 길 수 있습니다. 대신 음식이 한꺼번에 몰려 나오지 않도록 순서를 맞추고 있어 천천히 브런치를 즐기기 좋은 분위기를 유지하려고 해요. 여유롭게 방문하실 분들은 오픈 직후보다 한 템포 지난 시간대가 조금 더 편합니다.','서교브런치로프/소식-02/image.webp','2026-04-01T11:00:00+09:00'::timestamptz),
('biz_013-news-03','biz_013','시즌 수프 함께 제공','날씨가 애매하게 쌀쌀한 날이 이어져 이번 주는 일부 브런치 메뉴에 시즌 수프를 함께 준비하고 있어요. 서교브런치로프의 식사는 커피와 함께 오래 머무르기 좋은 구성이 장점이라, 너무 강한 맛보다는 부드럽게 이어지는 조합을 중심으로 맞추고 있습니다. 수프는 매일 수량이 많지 않아 늦은 시간에는 조기 종료될 수 있어요. 평소보다 든든한 구성을 찾는 분들이 좋아해주셔서 한동안 반응을 보며 이어갈 예정입니다.','서교브런치로프/소식-03/image.webp','2026-03-31T23:00:00+09:00'::timestamptz),
('biz_014-news-01','biz_014','러닝머신 구역 혼잡 시간 안내','망원헬스스테이션은 최근 저녁 시간 러닝머신 이용이 몰려 혼잡한 시간이 뚜렷해졌어요. 출근 전 운동하시는 분보다 퇴근 후 가볍게 유산소만 하고 가는 분들이 늘어서, 특정 시간대에는 웨이트보다 유산소 기구 대기 문의가 더 많습니다. 처음 등록하시는 분들은 시간대에 따라 체감이 많이 다를 수 있어 방문 전에 흐름을 확인하시는 게 좋아요. 비교적 여유 있는 시간에는 자세 체크나 기구 적응도 훨씬 편하게 하실 수 있습니다.','망원헬스스테이션/소식-01/image.webp','2026-03-31T13:00:00+09:00'::timestamptz),
('biz_014-news-02','biz_014','초보 회원 기구 안내 강화','운동을 처음 시작하는 회원분들이 늘면서 망원헬스스테이션은 기본 기구 사용 안내를 조금 더 자세히 진행하고 있어요. 무게를 무리해서 올리기보다 자주 쓰는 기구를 안전하게 익히는 쪽이 훨씬 오래 가기 때문에, 초반에는 루틴을 단순하게 가져가도록 설명드리고 있습니다. 특히 스쿼트랙이나 케이블 머신을 어려워하시는 분들이 많아 기본 동선부터 차근히 안내하는 편이에요. 혼자 운동해도 덜 막막하게 느끼셨다는 피드백이 많았습니다.','망원헬스스테이션/소식-02/image.webp','2026-03-31T03:00:00+09:00'::timestamptz),
('biz_015-news-01','biz_015','떡볶이 맵기 단계 조정 가능','합정분식연구소는 기본 떡볶이 맛이 가장 많이 나가지만, 맵기 조절 요청이 꾸준히 있어 주문 시 안내드리고 있어요. 너무 자극적인 맛보다 계속 손이 가는 분식 스타일을 좋아하시는 분들이 많아 기본 간은 세지 않게 잡았고, 조금 더 칼칼하게 드시고 싶은 분들만 선택할 수 있게 운영 중입니다. 튀김이나 순대와 같이 드시는 비율이 높아 전체 조합이 무겁지 않도록 맞추고 있어요. 근처에서 간단히 한 끼 먹고 가기 좋은 구성으로 많이 찾아주십니다.',null,'2026-03-30T14:00:00+09:00'::timestamptz),
('biz_015-news-02','biz_015','모둠 튀김 구성 바뀌었어요','자주 주문되는 조합을 반영해서 모둠 튀김 구성을 살짝 손봤어요. 합정분식연구소는 떡볶이와 함께 곁들이기 좋은 바삭한 메뉴 반응이 좋아, 너무 종류를 많이 늘리기보다 실제로 손이 자주 가는 재료 위주로 정리했습니다. 오래 두고 먹기보다는 바로 먹었을 때 가장 맛있는 식감을 기준으로 튀김 타이밍도 맞추고 있어요. 포장도 가능하지만 바삭함을 중요하게 생각하시는 분들은 매장 식사를 더 추천드립니다.',null,'2026-03-30T05:00:00+09:00'::timestamptz),
('biz_015-news-03','biz_015','늦은 오후 간식 세트 시작','오후 늦게 허기질 때 부담 없이 먹을 수 있게 작은 간식 세트를 새로 준비했어요. 떡볶이 양을 너무 많지 않게 하고 튀김이나 음료를 가볍게 더한 구성이라 혼자 방문하시는 분들이 특히 많이 찾고 있습니다. 합정분식연구소는 학생부터 직장인까지 손님층이 넓어 시간대마다 찾는 메뉴가 다른 편인데, 이번 세트는 애매한 시간대 수요를 반영해서 만들었어요. 간단하지만 분식다운 만족감은 남기도록 구성 균형을 많이 고민했습니다.',null,'2026-03-29T16:00:00+09:00'::timestamptz),
('biz_016-news-01','biz_016','증명사진 보정 톤 정리했어요','서교사진관오늘은 최근 증명사진 촬영 비중이 높아지면서 보정 톤을 조금 더 자연스럽게 정리하고 있어요. 과하게 다른 사람처럼 보이는 보정보다는 실제 인상은 유지하면서 피부톤과 잔머리, 표정 균형을 다듬는 쪽을 선호하시는 분들이 많았습니다. 취업용이나 여권용처럼 목적에 따라 강조해야 하는 기준이 달라 촬영 전 간단한 상담 시간을 꼭 두고 있어요. 원하는 분위기가 있다면 기존 사진을 보여주시면 방향을 맞추는 데 큰 도움이 됩니다.',null,'2026-03-29T03:00:00+09:00'::timestamptz),
('biz_016-news-02','biz_016','프로필 촬영 배경 선택 폭 확대','가벼운 개인 프로필 문의가 늘어서 배경 선택 폭을 조금 더 넓혔어요. 서교사진관오늘은 과한 콘셉트 촬영보다는 일상과 업무 모두에 어울리는 깔끔한 이미지를 많이 촬영하는 편이라, 표정과 자세를 어색하지 않게 잡아드리는 데 신경을 쓰고 있습니다. 처음 촬영하시는 분들은 카메라 앞에서 긴장하는 경우가 많지만, 테스트 컷을 보며 천천히 조정해드리고 있어 부담을 덜 느끼셨다는 이야기가 많아요. 예약 시간보다 조금 일찍 오시면 준비가 더 편합니다.',null,'2026-03-28T18:00:00+09:00'::timestamptz),
('biz_017-news-01','biz_017','오전 구움과자 수량 늘렸어요','망원베이크하우스는 최근 오전 시간대 방문이 늘어 스콘과 휘낭시에, 소금빵 같은 구움과자 수량을 조금 더 준비하고 있어요. 빵을 한 번에 많이 늘리기보다 잘 나가는 종류를 안정적으로 굽는 쪽을 택하고 있어서, 늦은 오후에는 선택 폭이 줄어들 수 있습니다. 특히 주말에는 커피와 함께 간단히 먹고 가는 손님보다 포장 손님 비중이 높아요. 원하는 품목이 있다면 조금 이른 시간 방문이 가장 만족도가 높습니다.',null,'2026-03-28T07:00:00+09:00'::timestamptz),
('biz_017-news-02','biz_017','레몬 파운드케이크 다시 나와요','문의가 많았던 레몬 파운드케이크를 이번 주부터 다시 진열해요. 망원베이크하우스의 파운드류는 과하게 묵직하기보다 차와 함께 먹기 편한 식감으로 맞추고 있어서, 달지만 부담이 적은 디저트를 찾는 분들이 자주 골라주십니다. 상큼한 향이 도는 메뉴라 오후 간식으로 찾는 손님 반응도 좋았어요. 수량이 많지 않아 늦은 시간에는 조기 소진될 수 있고, 다른 구움과자와 함께 묶어 포장하시는 분들이 특히 많습니다.',null,'2026-03-27T22:00:00+09:00'::timestamptz),
('biz_018-news-01','biz_018','평일 저녁 진료 접수 안내','합정정형케어의원은 퇴근 후 방문하시는 분들이 많아 평일 저녁 접수 흐름을 다시 안내드려요. 어깨, 허리, 손목처럼 오래 앉아 있거나 반복 사용으로 생기는 불편감 상담이 가장 많고, 증상에 따라 물리치료나 추가 검사를 연결해 설명드리고 있습니다. 짧게 참고 넘기다 통증이 커진 뒤 오시는 경우가 많아, 일상 동작에서 불편이 반복되면 너무 오래 미루지 않는 편을 권하고 있어요. 접수 마감 전에는 대기 인원이 갑자기 늘 수 있으니 조금 여유 있게 방문해 주세요.',null,'2026-03-27T12:00:00+09:00'::timestamptz),
('biz_018-news-02','biz_018','도수치료 전 상담 강화','최근에는 치료 자체보다 내 몸 상태를 먼저 정확히 알고 싶다는 문의가 많아서, 합정정형케어의원에서는 도수치료 전 상담 설명을 더 자세히 드리고 있어요. 통증 부위를 바로 강하게 풀기보다 왜 그 불편이 반복되는지 생활 습관과 자세를 함께 보는 편이라 이해가 쉽다는 반응이 있었습니다. 증상과 목표가 사람마다 달라 동일한 방식으로 진행하지 않고, 필요한 경우 운동이나 스트레칭 방향까지 같이 안내해드려요. 처음 내원하시는 분들도 과정을 미리 알고 오시면 훨씬 덜 부담스럽습니다.','합정정형케어의원/소식-02/image.webp','2026-03-26T23:00:00+09:00'::timestamptz),
('biz_019-news-01','biz_019','소형견 미용 예약 많아졌어요','서교반려미용실은 최근 소형견 기본 미용 예약이 크게 늘어 시간표를 조금 조정했어요. 털을 짧게 미는 것보다 아이가 스트레스를 덜 받는 범위에서 얼굴선과 발바닥, 위생 케어를 균형 있게 하는 요청이 많았습니다. 예민한 아이들은 낯선 공간에 적응하는 시간이 필요해서 처음 방문 시에는 예상보다 조금 더 여유가 필요할 수 있어요. 보호자분이 평소 싫어하는 부위나 주의할 점을 미리 알려주시면 훨씬 안전하게 진행할 수 있습니다.',null,'2026-03-26T12:00:00+09:00'::timestamptz),
('biz_019-news-02','biz_019','목욕 단독 케어도 가능합니다','전체 미용까지는 필요 없고 목욕과 말리기, 간단한 위생 정리만 원하는 보호자분들이 많아 관련 문의를 자주 받고 있어요. 서교반려미용실은 아이 컨디션을 우선으로 보기 때문에, 털 상태와 피부 상태를 확인한 뒤 필요한 케어 범위를 먼저 설명드리고 있습니다. 산책 후 흙먼지나 냄새 정리가 목적이라면 목욕 단독 케어만으로도 충분한 경우가 많아요. 미용 경험이 적은 아이들은 짧은 케어부터 익숙해지도록 도와드리는 편입니다.','서교반려미용실/소식-02/image.webp','2026-03-26T03:00:00+09:00'::timestamptz),
('biz_020-news-01','biz_020','오늘의 덮밥 구성 변경','합정일본가정식온기는 매일 비슷하지만 조금씩 다른 집밥 느낌을 유지하려고, 오늘의 덮밥 구성을 계절 식재료에 맞춰 가볍게 바꾸고 있어요. 너무 화려한 메뉴보다 편하게 한 끼 먹고 가는 가정식 스타일을 좋아해주시는 분들이 많아서 간도 과하지 않게 맞추고 있습니다. 점심에는 직장인 손님 비중이 높아 빠르게 나가는 메뉴를 중심으로 준비하고, 저녁에는 조금 더 천천히 드실 수 있는 구성을 추천드리고 있어요. 따뜻하고 무난한 식사를 찾는 분들에게 특히 잘 맞습니다.',null,'2026-03-25T18:00:00+09:00'::timestamptz),
('biz_020-news-02','biz_020','생선정식 수량 한정 운영','최근에는 생선정식을 찾는 손님이 늘어 수량을 정해 두고 운영하고 있어요. 합정일본가정식온기의 정식 메뉴는 반찬과 국, 밥까지 한 세트로 균형 있게 드실 수 있도록 구성하는 쪽에 초점을 두고 있어, 재료 준비량을 무리하게 늘리기보다 맛과 흐름을 안정적으로 맞추는 편입니다. 바쁜 시간에는 먼저 준비된 수량이 빠르게 소진될 수 있어요. 특정 메뉴를 생각하고 오시는 분들은 점심 초반이나 저녁 시작 시간 방문이 가장 안전합니다.',null,'2026-03-25T07:00:00+09:00'::timestamptz);
